var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 이쪽일 거예요. 언니를 찾으러 자주 가서 길은 다 외웠거든요.","JPN":"あ、こっちです。リタお姉ちゃんを探しによく通っていたから、道は全部覚えているんですよ。","ENG":"Oh, I think it's this way. I already memorized how to get there because I had to go looking for Rita all the time.","TWN":"啊，可能是這邊。之前經常到那裡去找姐姐，我記得路。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그 때는 저보다 언니가 더 힘들었을 거예요. 신호가 잡히는 곳까지는 아주 멀었거든요.","JPN":"そしてあの時は私よりリタお姉ちゃんのほうが辛かったと思います。信号の場所まではかなり距離があって。","ENG":"I'm sure Rita had a much tougher time than me back then. It took forever to get to a spot where we could find the signal.","TWN":"那時候姐姐應該比我更累。距離感應到信號的地方還很遠呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"저도 CRF가 넉넉하진 않아서...... 침식체들을 피해 가느라 멀리 돌아가야 했어요.","JPN":"私もCRFに余裕がなくて……侵食体を避けて遠回りをする必要がありました。","ENG":"And since I was also running pretty low on CRF... We had to take the long way around to avoid the Corrupted Objects.","TWN":"我的CRF也不充足……要躲避侵蝕體，所以要繞很遠的路。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그거 아세요? 리타 언니는 항상 저보다 늦게 잠들었어요. 술에 잔뜩 취한 채로요.","JPN":"知っていますか？　リタお姉ちゃんはいつも私より遅く寝ていたんです。ずいぶんと酔っ払ったまま。","ENG":"Did you know? Rita always went to bed later than me. Always plastered too.","TWN":"您知道嗎？麗塔姐姐總是比我睡得晚，醉醺醺的。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔은 제가 자고 있는 얼굴을 그려 뒀다가 보여 주시기도 했고요.","JPN":"たまに私の寝顔を描いて、見せてくれたりもしていました。","ENG":"Sometimes, she sketched my face while I was asleep and showed it to me later.","TWN":"偶爾會畫出我睡覺時候的樣子後拿給我看。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잠들었을 때도 얼빠지게 생겼다면서.","JPN":"寝ている時もマヌケな顔しているって。","ENG":"She teased me about how stupid I looked even when I was asleep.","TWN":"她說我睡覺的時候也很傻。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그날...... 언니가 왜 술을 못 끊는지 알게 됐어요.","JPN":"あの日……リタお姉ちゃんがなぜお酒をやめられなくなったのかを知りました。","ENG":"That day... I learned why she couldn't quit drinking.","TWN":"那天……我知道姐姐為什麼不能戒酒了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엄마...... 조금만 참아...... 내가 금방 꺼내 줄게......!","JPN":"母さん……少しだけ我慢して……今すぐ出してあげるから……！","ENG":"Mom... Hang in there... I'll get you out!","TWN":"媽媽……再忍一忍……我馬上救你出來……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 아무도 도와 주지 않는 거야......! 엄마가 살려달라잖아!","JPN":"なぜ誰も助けてくれないの……！　母さんが助けてって言っているのに！","ENG":"Why isn't anyone helping? My mom needs help!","TWN":"為什麼沒人幫忙……！媽媽在求救啊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엄마......! 엄마......!","JPN":"母さん……！　母さん……！","ENG":"Mom! Mom!","TWN":"媽媽……！媽媽……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"......이마에 식은땀을 닦아 주느라 소매가 축축하게 젖을 정도였거든요.","JPN":"……額の冷や汗がびっしょりで、袖でぬぐい切れないほどでした。","ENG":"She was covered in a cold sweat, so much so that my sleeves got soaked when I patted her head dry.","TWN":"……我給她擦額頭上的冷汗時袖子都濕了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"호라이즌 대표님은 뭔가 아실 것 같아서, 잠들기 전에 무슨 일인지 물어 봤어요.","JPN":"ホライズン代表なら何か知っていそうで、寝る前に聞いてみたんです。","ENG":"I thought my boss Horizon might know something about it, so I asked her before I went to bed.","TWN":"地平線BOSS好像知道什麼，我問他睡著之前發生了什麼事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 모친 말씀이십니까?","JPN":"リタの母親のことですか？","ENG":"Rita's mother?","TWN":"是說麗塔的母親嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네. 잠들었을 때 언니가 저런 잠꼬대를 하는지 전혀 몰랐어요.","JPN":"はい。リタお姉ちゃんがあんな寝言を言うなんて全然知らなかったです。","ENG":"Yes. I didn't realize Rita talked in her sleep like that.","TWN":"是，我睡著的時候完全不知道姐姐會說夢話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"평소보다 과하긴 하더군요. 침식 증후군일 가능성도 고려해야겠습니다.","JPN":"普段よりひどいですね。侵食症候群である可能性も考えなければなりません。","ENG":"It was more intense than usual. We may have to consider the possibility of Corruption Syndrome.","TWN":"是比平時嚴重了一些，可能是侵蝕症候群。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제가 얘기했다는 건 비밀로 해 주십시오.","JPN":"私が話したというのは内緒にしてください。","ENG":"Please don't tell her that I told you this.","TWN":"不能跟她說是我告訴你的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}}]`);export{e as default};